var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 놔! 빌어먹을 늙다리!","JPN":"放せ！　クソジジイ！","ENG":"Get off of me, you bloody old man!","TWN":"把我放下！你這該死的老頭！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 사람을 어디로 끌고 가는 거야!","JPN":"いったいどこに連れてこうってんだよ！","ENG":"Where are you taking me?","TWN":"你到底要把我帶到哪裡去啊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하핫. 카지노에서 두들겨 맞을 뻔한 걸 구해 줬더니 고맙다는 말도 없군.","JPN":"ハハッ。カジノで袋叩きにされそうだったところを助けてやったのに、お礼も言えないのか。","ENG":"Hah hah! I saved your bacon from those angry gamblers at the casino. You should be thanking me.","TWN":"哈哈。我明明救了在賭場差點挨揍的你，結果連句感謝的話都沒有啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 괜히 끼어들어서 판을 뒤집으려고 드나?","JPN":"なんでわざわざゲームをメチャクチャにしようとしたんだ？","ENG":"Why did you have to stick your nose in their games in the first place?","TWN":"為什麼要無緣無故插手管這件事？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"속임수 쓰는 놈이 있는데 멍청하게 돈 갖다 바치는 녀석들이 안쓰러워서 그랬다, 왜?","JPN":"相手がイカサマしてるのに、馬鹿みたいに\\n全財産を賭けようとしてる奴らが哀れだったんだよ！\\n悪いか？","ENG":"I was feeling sorry for those twits who didn't even know they were being scammed. So what?","TWN":"看到有人笨笨地把錢獻給出老千的傢伙，因為實在太可悲了我才這麼做的，怎嘛？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"혈기왕성하군.","JPN":"血気旺盛だな。","ENG":"You're one feisty young man.","TWN":"真是血氣方剛啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 정의감으로 나서는 것도 상황 봐 가면서 해야지.","JPN":"だが、正義感から手を出すにしても状況は見るべきだろう。","ENG":"But you should be careful not to let your sense of justice get you into trouble.","TWN":"但表現正義感之前還是得先看清楚情況吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기시네! 백주대낮에 사람을 납치하면서 뭐 그리 뻔뻔해?","JPN":"ふざけんな！　真昼間から人を拉致してるくせに、図々しいじじいだな！","ENG":"Hah! Says an old crook who's kidnapping a person in broad daylight.","TWN":"真是搞笑！光天化日之下綁架別人，還說得這麼大言不慚？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자고로 신사는 언제 어디서나 여유가 있어야 하는 법이야.","JPN":"紳士たるもの、いつでもどこでも余裕を持たなければ。","ENG":"A gentleman should be able to keep his composure at any time and place.","TWN":"自古以來，紳士無論何時何地，都要表現得遊刃有餘啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 불안해하면 볼썽사납다네.","JPN":"そんなにビビっているのは見苦しいぞ。","ENG":"He shouldn't express his fear and anxiety so bluntly.","TWN":"表現出慌張不安的樣子，實在太失體面了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그딴 소리는 놓고나 말하라고! 이 망할 할배가 진짜!!","JPN":"だったら放せよな！　このくそじじい！","ENG":"I'll pretend to listen if you let go of me. Come on, you barmy codger!","TWN":"不准說這種話！你這個該死的老頭！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까...... 그녀가 그 동안 그라운드 원의 대학원에서 재학 중이었다는 말인가요?","JPN":"つまり……彼女はこれまでグラウンド・ワンの大学院に在学中だったということですか？","ENG":"So... She has been studying at a graduate school in Ground One until now.","TWN":"所以……你是說，她這段時間一直在Ground 1的研究所念書？"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"네, 아가씨.","JPN":"はい、お嬢様。","ENG":"Yes, Lady Elizabeth.","TWN":"是的，小姐。"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"조사에 따르면 최근에 어머니의 부고를 받고 영지로 돌아갔다고 합니다.","JPN":"調査によると最近、母親の訃報を受けて領地に戻ったそうです。","ENG":"Our recent investigation discovered that she returned to the estate after hearing of her mother's death.","TWN":"根據調查，她是最近接到母親的訃告，才回到麥克蕾蒂領地的。"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"과연. 그래서 맥크레디 포인트에 자유롭게 드나들 수 있었던 거군요.","JPN":"なるほど。それでマクレディーポイントを自由に歩き回れたのですね。","ENG":"I see. That's why she was able to move in and out of MacCready Point freely.","TWN":"原來如此。所以她才能自由出入麥克蕾蒂要點啊。"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 자신이 누구인지는 전혀 몰랐던 모양이죠?","JPN":"でも、自分が何者かはまったく知らなかったようですけれど。","ENG":"So she had no idea who she was?","TWN":"但她好像完全不知道自己是什麼人的樣子？"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 정황을 보면 아마도 그런 것 같습니다.","JPN":"ええ。状況を見るにそのようです。","ENG":"No. At least it appears so, judging from the circumstances.","TWN":"是的。從狀況來看應該是這樣。"},"stage":{"bg":"SS_ESPR_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여어! 데리고 왔네. 혹시 내가 이야기를 방해한 건 아니겠지?","JPN":"おい！　お連れしたぞ。もしかして、邪魔したか？","ENG":"Hey! I've brought him. I hope I'm not interrupting anything.","TWN":"喲！我把他帶來啦。沒打擾到你們說話吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아닐세, 때맞춰 도착했군, 모건.","JPN":"いや、ちょうどよかったぞ、モーガン。","ENG":"No, you're just on time, Morgan.","TWN":"沒有，你來得正好，摩根。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"수고 많았어요. 그 원숭이가 버넷 경의 손자인가요?","JPN":"お疲れ様です。その猿が、バーネット卿の孫ですか？","ENG":"Good work. Is that monkey the grandson of Sir Burnett?","TWN":"辛苦了。這隻猴子就是伯內特卿的孫子嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 너 지금 나더러 원숭이라고 했냐?","JPN":"は？　お前、俺に向かって猿って言ったか？","ENG":"Huh? Did you just call me monkey?","TWN":"什麼？妳剛才是叫我猴子嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 모습을 보니 원숭이들에게 실례를 해버린 것 같군요, 물벼룩.","JPN":"その様子を見る限り猿以下ですわね、ミジンコ。","ENG":"Oh, I'm sorry. It'd be an insult to monkeys, Mr. Water Flea.","TWN":"看你這樣子，我似乎對猴子們太無禮了，水蚤。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이게...... 지금 나랑 싸우자는 거냐?","JPN":"この……ケンカ売ってんのか？","ENG":"Blimey... Are you trying to pick a fight with me?","TWN":"妳這……是想和我打架嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"주제 파악을 하세요. 당신이 제가 시비를 걸 만한 상대라도 된다고 생각하나요?","JPN":"身の程を知らないようですわ。私は、あなたがケンカを売ってもいい相手ではありません。","ENG":"Oh, please. What makes you think I'd pick a fight with a brute like you?","TWN":"請有點自知之明。你認為自己是值得我去挑釁的對手嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 경의 손자가 아니었다면 당신 같은 사람은 저와 이렇게 마주할 기회도 없었을 테니까요.","JPN":"バーネット卿の孫じゃなかったら、私はあなたに会うことすらなかったでしょう。","ENG":"I wouldn't even be talking to someone like you if you weren't Sir Burnett's grandson.","TWN":"你如果不是伯內特卿的孫子，你這種人連像這樣和我見面的機會都沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......우리 할배를 알아?","JPN":"……俺のじいさんのこと、知ってるのか？","ENG":"Do you know Grandpa?","TWN":"……妳認識我爺爺？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너 뭐야, 대체?","JPN":"お前、いったい何者だ？","ENG":"Who the heck are you?","TWN":"妳到底是誰？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그분은 우리 기관 역대 최고의 요원이셨습니다.","JPN":"あの方は、本機関の歴代最高のエージェントでした。","ENG":"Your grandfather was one of the best agents to have ever worked in the Institution.","TWN":"妳爺爺是我們機關歷代最優秀的要員。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"품위도 학식도 미래도 없어 보이는 당신과는 다르게 말이죠.","JPN":"品も学も未来もなさそうな、あなたとは違って。","ENG":"He was nothing like you, who doesn't seem to have any grace, knowledge, or future.","TWN":"不同於你這種看上去，品味、學識、未來都沒有的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그러셔? 내가 아는 할배랑은 좀 다른 것 같은데?","JPN":"ああ、そうかよ？　悪いけど、俺の知ってるじいさんとは少し違うな。","ENG":"Oh, really? I don't think we're talking about the same person then.","TWN":"喔，是喔？好像和我認識的爺爺有點不一樣呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 할배는 이런 괴짜들 모임 같은 곳과는 인연이 없는 평범한 사람이라고!","JPN":"俺のじいさんは、こんな変人の集まりみたいな所とは無縁な、平凡な人なんだよ！","ENG":"Grandpa was an average man. He couldn't have gotten involved in any business with you freaks.","TWN":"我爺爺和這種一堆怪人的地方無緣，他只是個的普通人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......은퇴 후에 버넷 형님이 좀 소탈한 삶을 즐기시긴 했지.","JPN":"……バーネットが引退後に、凡人のような余生を楽しんだのは確かだ。","ENG":"It's true that Burnett chose to lead a carefree life after retirement.","TWN":"……看來伯內特大哥引退後過得很愜意啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우릴 훈련시킬 땐 구층 지옥에서 올라온 악마 같았는데 말이야.","JPN":"私たちの訓練を受け持った時は、地獄から蘇った悪魔のようだったのにな。","ENG":"He was like a demon from the depth of hell when he was training us.","TWN":"明明訓練我們的時候，像個從九重地獄來的惡魔一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네도 근접 전투 배울 때 꽤 시달렸지 않나, 라이언?","JPN":"君も近接戦を教わる時、かなり大変だっただろう？","ENG":"You also had it rough during the CQC drills, didn't you, Ryan?","TWN":"你在學習近身戰鬥時，不是也飽受折磨嗎，瑞安？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"악마 같은 게 아니라 악마 그 자체였지.","JPN":"悪魔のようじゃなくて、悪魔そのものだったよ。","ENG":"He wasn't like a demon. He was the demon himself.","TWN":"他不是像惡魔，而是本身就是惡魔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부탁이니까 나쁜 기억 떠올리게 하지 말게, 모건.","JPN":"頼むからトラウマを蘇らせないでくれ、タデウス。","ENG":"Please, Morgan. Don't make me recall terrible memories.","TWN":"算我求你了，別讓我想起痛苦的回憶，摩根。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 당신들 정말 우리 할배와 아는 사이야?","JPN":"な、何だ？　お前ら、本当にじいさんと知り合いか？","ENG":"Huh? Do you really know my Grandpa?","TWN":"什、什麼？你們真的認識我爺爺？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 왜 날 여기로 데려온 거야?","JPN":"なんで俺をここへ連れてきたんだ？","ENG":"Then why did you bring me here?","TWN":"那幹嘛把我帶到這裡來？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......최근에 벌어진 일련의 사건으로 인해 우리 기관에도 새로운 인력 수급이 필요하다는 판단을 하게 됐습니다.","JPN":"……最近起きた一連の事件によって、この機関にも新しい人材が必要だと判断しました。","ENG":"A series of events that we experienced recently led us to think that the Institution will need to enhance its talent pool.","TWN":"……由於最近發生的一連串的事件，我認為我們機關也需要新的人才。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신 같은 물벼룩이 제 높은 기대치의 2%라도 만족시킬 수 있을지는 모르겠지만, 버넷 경의 체면을 생각해서 기회 정도는 드리도록 하죠.","JPN":"あなたのようなミジンコに、私の期待に応えることができるか疑わしいですが、\\nバーネット卿に免じてチャンスを与えましょう。","ENG":"I doubt a water flea like you could live up to my expectations at all, but I'll give you a chance for what Sir Burnett did to the Institution.","TWN":"雖然不知道你這樣的水蚤能不能能達到我期待的2%，但看在伯內特卿的面子上，還是給你個機會吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기회? 뭔 기회?","JPN":"チャンス？　何のチャンスだ？","ENG":"Chance? What chance?","TWN":"機會？什麼機會？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세상의 진실을 알 기회.","JPN":"世界の真実を知るチャンスです。","ENG":"A chance to embrace the truth.","TWN":"知道世界真實的機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"저게...... 뭐야?","JPN":"何だ……あれ？","ENG":"What's... that?","TWN":"那是……什麼？"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트의 마왕이라고 불리는 신성 침식체.","JPN":"クリフォトの魔王と呼ばれる神聖侵食体。","ENG":"It's a fragment of the Devourer Gha'agsheblah,","TWN":"被稱為逆卡巴拉魔王的神聖侵蝕體。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"탐식자, 가아그셰블라의 파편입니다.","JPN":"貪食者、ガアグシェブラの破片です。","ENG":"one of the Divine Corrupted Objects known as the Demon Lords of Qliphoth.","TWN":"貪食者，加格舍夫拉的碎片。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"가아그...... 뭐?","JPN":"ガアグ……何だって？","ENG":"Gha'ag... what?","TWN":"貪食者加格……什麼？"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 프리드웬 기관은 오래 전부터 저 마왕을 이곳에 가둬 두기 위해 존재해 왔답니다.","JPN":"プリドウェン機関は、昔からあの魔王をここへ封じ込めるために存在しました。","ENG":"Keeping the Demon Lord sealed here has been at the core of Prydwen Institution's existence since ages ago.","TWN":"我們普利多溫機關從以前，就是為了把那個魔王關在這裡而存在的。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 앞으로 당신이 해야 할 일이기도 하죠.","JPN":"そして、これからあなたがやるべき仕事でもあります。","ENG":"And it will be at the core of your existence from now on.","TWN":"而這也是你日後要做的事情。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 기관의 비밀 격리 시설, LAKE - 4에 온 것을 환영합니다.","JPN":"プリドウェン機関の秘密隔離施設、LAKE-4へようこそ。","ENG":"Welcome to LAKE-4, Prydwen Institution's top secret quarantine facility,","TWN":"歡迎來到普利多溫機關的秘密隔離設施， LAKE - 4。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷.","JPN":"ロイ・バーネット。","ENG":"Roy Burnett.","TWN":"羅伊·伯內特。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};